import React, { useState, useEffect, useMemo, useRef } from 'react';

const theme = {
  bg: '#0a0a0a', surface: '#141414', card: '#1a1a1a', border: '#2a2a2a',
  text: '#fafafa', muted: '#a1a1aa', dim: '#52525b',
  blue: '#38bdf8', green: '#4ade80', purple: '#a78bfa',
  yellow: '#fbbf24', pink: '#f472b6', orange: '#fb923c', red: '#f87171',
};

const det3 = (m) =>
  m[0][0] * (m[1][1] * m[2][2] - m[1][2] * m[2][1]) -
  m[0][1] * (m[1][0] * m[2][2] - m[1][2] * m[2][0]) +
  m[0][2] * (m[1][0] * m[2][1] - m[1][1] * m[2][0]);

const fmt = (v) => {
  if (Math.abs(v) < 0.00005) return '0';
  const s = v.toFixed(4);
  return s.replace(/\.?0+$/, '');
};

const presets = [
  { name: 'Default', A: [[2,-1,3],[4,2,1],[-6,1,-2]], b: [5,10,-3] },
  { name: 'Diagonal', A: [[3,0,0],[0,2,0],[0,0,5]], b: [9,8,15] },
  { name: 'Singular', A: [[1,2,3],[4,5,6],[7,8,9]], b: [1,2,3] },
];

const colColors = [theme.blue, theme.purple, theme.yellow];

export default function App() {
  const [A, setA] = useState(presets[0].A.map(r => [...r]));
  const [b, setB] = useState([...presets[0].b]);
  const [activeCol, setActiveCol] = useState(null);
  const [isPlaying, setIsPlaying] = useState(false);
  const [playIdx, setPlayIdx] = useState(-1);
  const [editKey, setEditKey] = useState(null);
  const [editVal, setEditVal] = useState('');
  const inputRef = useRef(null);

  const detA = useMemo(() => det3(A), [A]);
  const isSingular = Math.abs(detA) < 1e-10;

  const solData = useMemo(() => {
    if (isSingular) return null;
    return [0, 1, 2].map(c => {
      const mod = A.map((row, i) => row.map((v, j) => j === c ? b[i] : v));
      const d = det3(mod);
      return { col: c, detMod: d, x: d / detA };
    });
  }, [A, b, detA, isSingular]);

  useEffect(() => {
    if (isPlaying) {
      const next = playIdx + 1;
      if (next > 2) { setIsPlaying(false); return; }
      const timer = setTimeout(() => {
        setPlayIdx(next);
        setActiveCol(next);
      }, 1800);
      return () => clearTimeout(timer);
    }
  }, [isPlaying, playIdx]);

  useEffect(() => {
    if (inputRef.current) inputRef.current.focus();
  }, [editKey]);

  const startPlay = () => {
    setPlayIdx(-1);
    setActiveCol(null);
    setIsPlaying(true);
    setTimeout(() => { setPlayIdx(0); setActiveCol(0); }, 300);
  };

  const reset = () => {
    setIsPlaying(false);
    setPlayIdx(-1);
    setActiveCol(null);
  };

  const loadPreset = (idx) => {
    const p = presets[idx];
    setA(p.A.map(r => [...r]));
    setB([...p.b]);
    setActiveCol(null);
    setIsPlaying(false);
    setPlayIdx(-1);
  };

  const startEdit = (key, val) => {
    setEditKey(key);
    setEditVal(String(val));
  };

  const commitEdit = () => {
    if (!editKey) return;
    const v = parseFloat(editVal);
    if (isNaN(v)) { setEditKey(null); return; }
    if (editKey.startsWith('a_')) {
      const [, r, c] = editKey.split('_').map(Number);
      const newA = A.map(row => [...row]);
      newA[r][c] = v;
      setA(newA);
    } else if (editKey.startsWith('b_')) {
      const r = parseInt(editKey.split('_')[1]);
      const newB = [...b];
      newB[r] = v;
      setB(newB);
    }
    setEditKey(null);
  };

  const activeSol = activeCol !== null && solData ? solData[activeCol] : null;
  const color = activeCol !== null ? colColors[activeCol] : theme.blue;

  const renderCell = (val, key, isReplaced, replacedColor) => {
    const isEditing = editKey === key;
    const bg = isReplaced ? replacedColor + '18' : theme.card;
    const border = isReplaced ? replacedColor + '50' : theme.border;
    const textColor = isReplaced ? replacedColor : theme.text;
    if (isEditing) {
      return (
        <input
          ref={inputRef}
          value={editVal}
          onChange={(e) => setEditVal(e.target.value)}
          onBlur={commitEdit}
          onKeyDown={(e) => { if (e.key === 'Enter') commitEdit(); if (e.key === 'Escape') setEditKey(null); }}
          style={{
            width: 52, height: 36, background: theme.surface, border: '2px solid ' + theme.blue,
            borderRadius: 6, color: theme.text, fontFamily: 'monospace', fontSize: 15,
            fontWeight: 600, textAlign: 'center', outline: 'none',
          }}
        />
      );
    }
    return (
      <div
        onClick={() => startEdit(key, val)}
        style={{
          width: 52, height: 36, display: 'flex', alignItems: 'center', justifyContent: 'center',
          background: bg, border: '1px solid ' + border, borderRadius: 6,
          fontFamily: 'monospace', fontSize: 15, fontWeight: 600, color: textColor,
          cursor: 'pointer', transition: 'all 0.4s ease', userSelect: 'none',
        }}
      >
        {typeof val === 'number' ? (Number.isInteger(val) ? val : fmt(val)) : val}
      </div>
    );
  };

  const insight = isSingular
    ? 'det(A) = 0, so the system has no unique solution. The matrix is singular - its columns are linearly dependent.'
    : activeCol !== null && solData
    ? `Replacing column ${activeCol + 1} with b gives det(A${activeCol + 1}) = ${fmt(activeSol.detMod)}. Dividing by det(A) = ${fmt(detA)} yields x${activeCol + 1} = ${fmt(activeSol.x)}.`
    : 'Click a column button below to replace it with b and compute the corresponding variable using Cramer\'s Rule.';

  return (
    <div style={{ background: theme.bg, minHeight: '100vh', display: 'flex', justifyContent: 'center', padding: '16px 12px' }}>
      <div style={{ maxWidth: 520, width: '100%' }}>
        {/* Header */}
        <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: 14 }}>
          <div>
            <h1 style={{ margin: 0, fontSize: 18, fontWeight: 700, color: theme.text }}>Cramer's Rule</h1>
            <div style={{ fontSize: 11, color: theme.dim, marginTop: 2 }}>Click cells to edit, columns to solve</div>
          </div>
          <div style={{ display: 'flex', gap: 8 }}>
            <button onClick={startPlay} style={{ width: 34, height: 34, borderRadius: 8, border: 'none', background: theme.green + '20', color: theme.green, cursor: 'pointer', fontSize: 16, display: 'flex', alignItems: 'center', justifyContent: 'center' }}>
              {isPlaying ? '||' : '>'}
            </button>
            <button onClick={reset} style={{ width: 34, height: 34, borderRadius: 8, border: 'none', background: theme.card, color: theme.muted, cursor: 'pointer', fontSize: 14, display: 'flex', alignItems: 'center', justifyContent: 'center' }}>
              R
            </button>
          </div>
        </div>

        {/* Presets */}
        <div style={{ display: 'flex', gap: 6, marginBottom: 16 }}>
          {presets.map((p, i) => (
            <button key={i} onClick={() => loadPreset(i)}
              style={{
                padding: '5px 12px', borderRadius: 6, border: '1px solid ' + theme.border,
                background: theme.card, color: theme.muted, fontSize: 11, cursor: 'pointer',
                fontFamily: 'monospace',
              }}
            >{p.name}</button>
          ))}
        </div>

        {/* Matrix Display */}
        <div style={{ background: theme.surface, borderRadius: 12, padding: 20, marginBottom: 14 }}>
          <div style={{ display: 'flex', alignItems: 'center', justifyContent: 'center', gap: 20 }}>
            {/* Matrix A with brackets */}
            <div style={{ display: 'flex', alignItems: 'center', gap: 0 }}>
              <div style={{ fontSize: 12, color: theme.dim, marginRight: 6, alignSelf: 'flex-start', marginTop: 8 }}>A =</div>
              <div style={{ borderLeft: '2.5px solid ' + theme.dim, borderTop: '2.5px solid ' + theme.dim, borderBottom: '2.5px solid ' + theme.dim, borderRadius: '4px 0 0 4px', padding: '6px 0 6px 4px' }}>
                <div style={{ display: 'flex', flexDirection: 'column', gap: 4 }}>
                  {A.map((row, r) => (
                    <div key={r} style={{ display: 'flex', gap: 4 }}>
                      {row.map((val, c) => {
                        const replaced = activeCol === c;
                        const displayVal = replaced ? b[r] : val;
                        return (
                          <div key={c}>
                            {renderCell(displayVal, replaced ? 'b_' + r : 'a_' + r + '_' + c, replaced, color)}
                          </div>
                        );
                      })}
                    </div>
                  ))}
                </div>
              </div>
              <div style={{ borderRight: '2.5px solid ' + theme.dim, borderTop: '2.5px solid ' + theme.dim, borderBottom: '2.5px solid ' + theme.dim, borderRadius: '0 4px 4px 0', width: 4, alignSelf: 'stretch' }} />
            </div>

            {/* Vector b */}
            <div style={{ display: 'flex', alignItems: 'center', gap: 0 }}>
              <div style={{ fontSize: 12, color: theme.dim, marginRight: 6, alignSelf: 'flex-start', marginTop: 8 }}>b =</div>
              <div style={{ borderLeft: '2.5px solid ' + theme.dim, borderTop: '2.5px solid ' + theme.dim, borderBottom: '2.5px solid ' + theme.dim, borderRadius: '4px 0 0 4px', padding: '6px 0 6px 4px' }}>
                <div style={{ display: 'flex', flexDirection: 'column', gap: 4 }}>
                  {b.map((val, r) => (
                    <div key={r}>
                      {renderCell(val, 'b_' + r, activeCol !== null, activeCol !== null ? color : theme.blue)}
                    </div>
                  ))}
                </div>
              </div>
              <div style={{ borderRight: '2.5px solid ' + theme.dim, borderTop: '2.5px solid ' + theme.dim, borderBottom: '2.5px solid ' + theme.dim, borderRadius: '0 4px 4px 0', width: 4, alignSelf: 'stretch' }} />
            </div>
          </div>

          {/* det(A) */}
          <div style={{ textAlign: 'center', marginTop: 14, fontFamily: 'monospace', fontSize: 13 }}>
            <span style={{ color: theme.dim }}>det(A) = </span>
            <span style={{ color: isSingular ? theme.red : theme.green, fontWeight: 700, fontSize: 15 }}>{fmt(detA)}</span>
            {isSingular && <span style={{ color: theme.red, fontSize: 11, marginLeft: 8 }}>(singular!)</span>}
          </div>
        </div>

        {/* Column Selector */}
        <div style={{ display: 'flex', gap: 8, justifyContent: 'center', marginBottom: 14 }}>
          {[0, 1, 2].map(c => {
            const isActive = activeCol === c;
            const cc = colColors[c];
            return (
              <button key={c}
                onClick={() => { if (!isSingular) { setActiveCol(isActive ? null : c); setIsPlaying(false); } }}
                style={{
                  padding: '8px 20px', borderRadius: 8,
                  border: isActive ? '2px solid ' + cc : '2px solid ' + theme.border,
                  background: isActive ? cc + '20' : theme.card,
                  color: isActive ? cc : theme.muted,
                  fontSize: 14, fontWeight: 700, cursor: isSingular ? 'not-allowed' : 'pointer',
                  fontFamily: 'monospace', transition: 'all 0.3s ease',
                  opacity: isSingular ? 0.4 : 1,
                }}
              >
                x{c + 1}
              </button>
            );
          })}
        </div>

        {/* Computation Display */}
        <div style={{ background: theme.surface, borderRadius: 12, padding: 16, marginBottom: 14, minHeight: 80 }}>
          {isSingular ? (
            <div style={{ textAlign: 'center', padding: 12 }}>
              <div style={{ fontSize: 14, fontWeight: 700, color: theme.red, marginBottom: 6 }}>No Unique Solution</div>
              <div style={{ fontSize: 12, color: theme.muted }}>det(A) = 0, so Cramer's Rule cannot be applied.</div>
            </div>
          ) : activeCol !== null && activeSol ? (
            <div>
              <div style={{ textAlign: 'center', marginBottom: 10 }}>
                <span style={{ fontSize: 12, color: theme.dim }}>Replace column </span>
                <span style={{ fontSize: 13, fontWeight: 700, color: color }}>{activeCol + 1}</span>
                <span style={{ fontSize: 12, color: theme.dim }}> of A with b</span>
              </div>
              <div style={{
                background: theme.bg, borderRadius: 8, padding: 12, fontFamily: 'monospace',
                textAlign: 'center', fontSize: 14, marginBottom: 10,
              }}>
                <span style={{ color: color, fontWeight: 700 }}>x{activeCol + 1}</span>
                <span style={{ color: theme.dim }}> = </span>
                <span style={{ color: theme.muted }}>det(A{activeCol + 1})</span>
                <span style={{ color: theme.dim }}> / </span>
                <span style={{ color: theme.muted }}>det(A)</span>
                <span style={{ color: theme.dim }}> = </span>
                <span style={{ color: theme.muted }}>{fmt(activeSol.detMod)}</span>
                <span style={{ color: theme.dim }}> / </span>
                <span style={{ color: theme.muted }}>{fmt(detA)}</span>
                <span style={{ color: theme.dim }}> = </span>
                <span style={{ color: color, fontWeight: 700, fontSize: 16 }}>{fmt(activeSol.x)}</span>
              </div>

              {/* Solution vector */}
              <div style={{ display: 'flex', justifyContent: 'center', gap: 12 }}>
                {solData.map((s, i) => (
                  <div key={i} style={{
                    padding: '6px 14px', borderRadius: 6,
                    background: activeCol === i ? color + '15' : theme.bg,
                    border: '1px solid ' + (activeCol === i ? color + '40' : theme.border),
                    transition: 'all 0.3s ease',
                  }}>
                    <div style={{ fontSize: 10, color: theme.dim, textAlign: 'center', marginBottom: 2 }}>x{i + 1}</div>
                    <div style={{
                      fontSize: 14, fontWeight: 700, textAlign: 'center',
                      color: activeCol === i ? color : theme.muted,
                      fontFamily: 'monospace', transition: 'all 0.3s ease',
                    }}>{fmt(s.x)}</div>
                  </div>
                ))}
              </div>
            </div>
          ) : (
            <div style={{ textAlign: 'center', padding: 8 }}>
              <div style={{ fontSize: 13, color: theme.dim, marginBottom: 4 }}>Select a variable to solve</div>
              <div style={{ fontSize: 11, color: theme.dim }}>Click x1, x2, or x3 above</div>
            </div>
          )}
        </div>

        {/* Insight */}
        <div style={{
          fontSize: 12, color: theme.muted, lineHeight: 1.6,
          borderLeft: '3px solid ' + (activeCol !== null ? color : theme.border),
          paddingLeft: 12, transition: 'border-color 0.3s ease',
        }}>
          {insight}
        </div>
      </div>
    </div>
  );
}
